// ---------------------------------------------------------------------------
// In-memory LRU Blocklist with generation-based invalidation
// Instead of checking a DB on every request, we maintain:
//   1. A small in-memory set of explicitly revoked JTI values (with auto-expiry)
//   2. A per-user "token generation" counter — tokens minted before the current
//      generation are considered invalid. This lets us mass-invalidate all tokens
//      for a user (e.g., password change) without a DB round-trip per request.
// ---------------------------------------------------------------------------

class TokenBlocklist {
  constructor(maxSize = 100_000) {
    this.maxSize = maxSize;
    this.blocked = new Map(); // jti -> expiry timestamp
    this.cleanupInterval = setInterval(() => this._cleanup(), 60_000);
  }

  add(jti, expiresAt) {
    if (this.blocked.size >= this.maxSize) {
      this._cleanup();
      // If still at capacity after cleanup, evict oldest entries
      if (this.blocked.size >= this.maxSize) {
        const entriesToRemove = Math.floor(this.maxSize * 0.1);
        const iterator = this.blocked.keys();
        for (let i = 0; i < entriesToRemove; i++) {
          const key = iterator.next().value;
          this.blocked.delete(key);
        }
      }
    }
    this.blocked.set(jti, expiresAt);
  }

  isBlocked(jti) {
    if (!this.blocked.has(jti)) return false;
    const expiresAt = this.blocked.get(jti);
    if (Date.now() > expiresAt * 1000) {
      this.blocked.delete(jti);
      return false;
    }
    return true;
  }

  _cleanup() {
    const now = Date.now();
    for (const [jti, expiresAt] of this.blocked) {
      if (now > expiresAt * 1000) {
        this.blocked.delete(jti);
      }
    }
  }

  destroy() {
    clearInterval(this.cleanupInterval);
    this.blocked.clear();
  }
}

// Per-user generation tracker (in production, back this with Redis with local cache)
class UserGenerationTracker {
  constructor() {
    // userId -> { generation: number, updatedAt: timestamp }
    this.generations = new Map();
  }

  getGeneration(userId) {
    const entry = this.generations.get(userId);
    return entry ? entry.generation : 0;
  }

  incrementGeneration(userId) {
    const current = this.getGeneration(userId);
    this.generations.set(userId, {
      generation: current + 1,
      updatedAt: Date.now(),
    });
    return current + 1;
  }

  isValidGeneration(userId, tokenGeneration) {
    const currentGeneration = this.getGeneration(userId);
    return tokenGeneration >= currentGeneration;
  }
}

