// ---------------------------------------------------------------------------
// Verification cache — avoid re-verifying the same JWT cryptographic signature
// within a short window. Uses a bounded Map as a simple LRU.
// ---------------------------------------------------------------------------

class VerificationCache {
  constructor(maxSize = 50_000, ttlMs = 30_000) {
    this.maxSize = maxSize;
    this.ttlMs = ttlMs;
    this.cache = new Map();
    this.cleanupInterval = setInterval(() => this._cleanup(), 15_000);
  }

  get(token) {
    const entry = this.cache.get(token);
    if (!entry) return null;
    if (Date.now() - entry.cachedAt > this.ttlMs) {
      this.cache.delete(token);
      return null;
    }
    return entry.decoded;
  }

  set(token, decoded) {
    if (this.cache.size >= this.maxSize) {
      // Evict oldest 10%
      const entriesToRemove = Math.floor(this.maxSize * 0.1);
      const iterator = this.cache.keys();
      for (let i = 0; i < entriesToRemove; i++) {
        this.cache.delete(iterator.next().value);
      }
    }
    this.cache.set(token, { decoded, cachedAt: Date.now() });
  }

  _cleanup() {
    const now = Date.now();
    for (const [key, entry] of this.cache) {
      if (now - entry.cachedAt > this.ttlMs) {
        this.cache.delete(key);
      }
    }
  }

  destroy() {
    clearInterval(this.cleanupInterval);
    this.cache.clear();
  }
}

const verificationCache = new VerificationCache();

