function extractToken(req) {
  // Check Authorization header first (most common)
  const authHeader = req.headers.authorization;
  if (authHeader) {
    const parts = authHeader.split(' ');
    if (parts.length === 2 && parts[0].toLowerCase() === 'bearer') {
      return parts[1];
    }
  }

  // Fallback: check query param (for websockets / SSE)
  if (req.query && req.query.token) {
    return req.query.token;
  }

  // Fallback: check cookie
  if (req.cookies && req.cookies.access_token) {
    return req.cookies.access_token;
  }

  return null;
}

function authenticateToken(options = {}) {
  const {
    required = true,
    roles = [],
    permissions = [],
  } = options;

  return (req, res, next) => {
    const token = extractToken(req);

    if (!token) {
      if (!required) {
        req.user = null;
        return next();
      }
      return res.status(401).json({
        error: 'MISSING_TOKEN',
        message: 'Authentication token is required',
      });
    }

    let decoded;

    // Check verification cache first (avoids crypto on hot path)
    const cached = verificationCache.get(token);
    if (cached) {
      decoded = cached;
    } else {
      try {
        decoded = jwt.verify(token, config.accessTokenSecret, {
          issuer: config.issuer,
          audience: config.audience,
          algorithms: ['HS256'],
          clockTolerance: 5, // 5 seconds tolerance for clock skew
        });
        verificationCache.set(token, decoded);
      } catch (err) {
        if (err.name === 'TokenExpiredError') {
          return res.status(401).json({
            error: 'TOKEN_EXPIRED',
            message: 'Authentication token has expired',
            expiredAt: err.expiredAt,
          });
        }
        if (err.name === 'JsonWebTokenError') {
          return res.status(401).json({
            error: 'INVALID_TOKEN',
            message: 'Authentication token is invalid',
          });
        }
        return res.status(401).json({
          error: 'TOKEN_ERROR',
          message: 'Token verification failed',
        });
      }
    }

    // Check blocklist (O(1) in-memory lookup)
    if (decoded.jti && blocklist.isBlocked(decoded.jti)) {
      return res.status(401).json({
        error: 'TOKEN_REVOKED',
        message: 'Authentication token has been revoked',
      });
    }

    // Check user generation (mass invalidation, O(1) in-memory lookup)
    if (decoded.gen !== undefined && !userGenerations.isValidGeneration(decoded.sub, decoded.gen)) {
      return res.status(401).json({
        error: 'TOKEN_INVALIDATED',
        message: 'Authentication token has been invalidated — please re-authenticate',
      });
    }

    // Role-based access check
    if (roles.length > 0) {
      const userRoles = decoded.roles || [];
      const hasRequiredRole = roles.some((role) => userRoles.includes(role));
      if (!hasRequiredRole) {
        return res.status(403).json({
          error: 'INSUFFICIENT_ROLE',
          message: `Required roles: ${roles.join(', ')}`,
        });
      }
    }

    // Permission-based access check
    if (permissions.length > 0) {
      const userPermissions = decoded.permissions || [];
      const hasAllPermissions = permissions.every((perm) => userPermissions.includes(perm));
      if (!hasAllPermissions) {
        return res.status(403).json({
          error: 'INSUFFICIENT_PERMISSIONS',
          message: `Required permissions: ${permissions.join(', ')}`,
        });
      }
    }

    // Attach user info to request
    req.user = {
      id: decoded.sub,
      email: decoded.email,
      roles: decoded.roles || [],
      permissions: decoded.permissions || [],
      tokenId: decoded.jti,
      tokenGeneration: decoded.gen,
      issuedAt: decoded.iat,
      expiresAt: decoded.exp,
    };

    next();
  };
}

// Convenience shortcuts
