function verifyRefreshToken(token) {
  const decoded = jwt.verify(token, config.refreshTokenSecret, {
    issuer: config.issuer,
    audience: config.audience,
    algorithms: ['HS256'],
  });

  if (decoded.type !== 'refresh') {
    throw new Error('Invalid token type');
  }

  if (decoded.jti && blocklist.isBlocked(decoded.jti)) {
    throw new Error('Refresh token has been revoked');
  }

  if (decoded.gen !== undefined && !userGenerations.isValidGeneration(decoded.sub, decoded.gen)) {
    throw new Error('Refresh token has been invalidated');
  }

  return decoded;
}

